/**
 * One-off / CI: builds courses-en-deep.js (English theory + challenge copy) from js/content.js
 * via Google translate client=gtx. Preserves <pre>…</pre> blocks untranslated.
 *
 * Usage: node js/build-course-en-deep-translate.mjs
 */
import fs from 'fs';
import vm from 'vm';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const CONTENT = path.join(__dirname, 'content.js');
const OUT = path.join(__dirname, 'courses-en-deep.js');
const HDR =
  '// Auto-generated by js/build-course-en-deep-translate.mjs — regenerate with: node js/build-course-en-deep-translate.mjs\n';

function flushDeep(deep) {
  fs.writeFileSync(OUT, HDR + 'window.COURSE_EN_DEEP = ' + JSON.stringify(deep) + ';\n', 'utf8');
}

/** Sidecar JSON for reliable resume (pure JSON, no brace-in-string issues). */
const PROGRESS_JSON = path.join(__dirname, 'courses-en-deep.progress.json');

function loadProgressDeep() {
  try {
    if (!fs.existsSync(PROGRESS_JSON)) return {};
    const o = JSON.parse(fs.readFileSync(PROGRESS_JSON, 'utf8'));
    return o && typeof o === 'object' ? o : {};
  } catch {
    return {};
  }
}

function flushProgressJson(deep) {
  fs.writeFileSync(PROGRESS_JSON, JSON.stringify(deep), 'utf8');
}

function loadCourses() {
  const lines = fs.readFileSync(CONTENT, 'utf8').split('\n');
  const code = lines.slice(0, 9709).join('\n').replace('const COURSES =', 'var __COURSES =');
  const ctx = {};
  vm.createContext(ctx);
  vm.runInContext(`${code}; this.__C = __COURSES;`, ctx);
  return ctx.__C;
}

const CYR = /[\u0400-\u04FF\u0490\u0491\u0404\u0454ҐґІіЇїЄє]/;

const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

async function fetchTranslateChunk(chunk) {
  const url =
    'https://translate.googleapis.com/translate_a/single?client=gtx&sl=uk&tl=en&dt=t&q=' +
    encodeURIComponent(chunk);
  let lastErr;
  for (let attempt = 0; attempt < 6; attempt++) {
    const res = await fetch(url);
    if (res.ok) {
      const j = await res.json();
      return j[0].map((x) => x[0]).join('');
    }
    lastErr = new Error(`translate HTTP ${res.status}`);
    const retry = res.status === 429 || res.status >= 500;
    if (!retry) throw lastErr;
    await sleep(900 * Math.pow(2, attempt) + Math.floor(Math.random() * 400));
  }
  throw lastErr;
}

async function gtx(text) {
  const t = String(text ?? '');
  if (!t.trim() || !CYR.test(t)) return t;
  const max = 4200;
  const parts = [];
  for (let i = 0; i < t.length; i += max) {
    const chunk = t.slice(i, i + max);
    parts.push(await fetchTranslateChunk(chunk));
    await sleep(320);
  }
  return parts.join('');
}

function stripPres(html) {
  const pres = [];
  const rx = /<pre[\s\S]*?<\/pre>/gi;
  let out = '';
  let last = 0;
  let m;
  let idx = 0;
  const s = String(html);
  while ((m = rx.exec(s))) {
    out += s.slice(last, m.index);
    const token = `[[[CODEBLOCK${idx++}]]]`;
    pres.push({ token, html: m[0] });
    out += token;
    last = m.lastIndex;
  }
  out += s.slice(last);
  return { text: out, pres };
}

function restorePres(text, pres) {
  let r = text;
  for (const { token, html } of pres) r = r.split(token).join(html);
  return r;
}

async function translateHtml(html) {
  const { text, pres } = stripPres(html);
  const tr = await gtx(text);
  return restorePres(tr, pres);
}

async function main() {
  const C = loadCourses();
  const deep = loadProgressDeep();
  let n = 0;
  for (const [cid, course] of Object.entries(C)) {
    for (const mod of course.modules || []) {
      for (const les of mod.lessons || []) {
        const key = `${cid}|${mod.id}|${les.id}`;
        n++;
        if (deep[key]) {
          process.stderr.write(`[${n}] ${key} — skip (resume)\n`);
          continue;
        }
        process.stderr.write(`[${n}] ${key}…\n`);
        try {
          const entry = { challenges: {} };
          if (les.theory) entry.theory = await translateHtml(les.theory);
          for (const ch of les.challenges || []) {
            const chEnt = {};
            if (ch.title) chEnt.title = await gtx(ch.title);
            if (ch.prompt) chEnt.prompt = await translateHtml(ch.prompt);
            if (ch.starterCode) chEnt.starterCode = await gtx(ch.starterCode);
            if (ch.tests?.length) {
              chEnt.tests = [];
              for (const t of ch.tests) {
                const te = {};
                if (t.desc != null && CYR.test(String(t.desc))) te.desc = await gtx(t.desc);
                if (t.expected != null && typeof t.expected === 'string' && CYR.test(t.expected)) {
                  te.expected = await gtx(t.expected);
                }
                chEnt.tests.push(te);
              }
            }
            entry.challenges[ch.id] = chEnt;
          }
          if (!Object.keys(entry.challenges).length) delete entry.challenges;
          deep[key] = entry;
          flushProgressJson(deep);
          flushDeep(deep);
        } catch (e) {
          process.stderr.write(`ERROR at ${key}: ${e.message}\n`);
          flushProgressJson(deep);
          flushDeep(deep);
          throw e;
        }
      }
    }
  }
  flushProgressJson(deep);
  flushDeep(deep);
  process.stderr.write(`Wrote ${OUT} (${Object.keys(deep).length} lessons)\n`);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
